import { useState } from 'react';

interface SearchBarProps {
  onSearch: (query: string) => void;
}

const SearchBar = ({ onSearch }: SearchBarProps) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<string[]>([]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setQuery(value);
    // Simulate fetching suggestions
    setSuggestions(value ? ['Suggestion 1', 'Suggestion 2', 'Suggestion 3'] : []);
  };

  const handleSearch = () => {
    onSearch(query);
  };

  return (
    <div className="relative">
      <input
        type="text"
        value={query}
        onChange={handleInputChange}
        className="w-full p-2 rounded-lg border border-gray-700 bg-gray-800 text-white"
        placeholder="Search..."
      />
      <button
        onClick={handleSearch}
        className="absolute right-2 top-1/2 transform -translate-y-1/2 px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition"
      >
        Search
      </button>
      {suggestions.length > 0 && (
        <ul className="absolute w-full bg-gray-800 border border-gray-700 rounded-lg mt-1">
          {suggestions.map((suggestion, index) => (
            <li
              key={index}
              className="p-2 hover:bg-gray-700 cursor-pointer"
              onClick={() => {
                setQuery(suggestion);
                setSuggestions([]);
              }}
            >
              {suggestion}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};

export default SearchBar;

