import React, { useRef, useState } from 'react';

interface VideoPlayerProps {
  videoSrc: string;
  captions?: string;
}

const VideoPlayer = ({ videoSrc, captions }: VideoPlayerProps) => {
  const videoRef = useRef<HTMLVideoElement | null>(null);
  const [playing, setPlaying] = useState(false);

  const togglePlay = () => {
    if (videoRef.current) {
      if (playing) {
        videoRef.current.pause();
      } else {
        videoRef.current.play();
      }
      setPlaying(!playing);
    }
  };

  return (
    <div className="relative">
      <video
        ref={videoRef}
        src={videoSrc}
        className="w-full rounded-xl shadow-md"
        controls
      >
        {captions && <track kind="captions" src={captions} />}
      </video>
      <button
        onClick={togglePlay}
        className="absolute bottom-4 left-4 px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition"
      >
        {playing ? 'Pause' : 'Play'}
      </button>
    </div>
  );
};

export default VideoPlayer;
